if 'SliceThickness' in value.columns and 'Count' in value.columns:
    slice_thickness = value['SliceThickness'].iloc[0]
    num_slices = value['Count'].iloc[0]
    coverage = slice_thickness * num_slices
    if coverage < 60:
        raise ValidationError(f"Insufficient slice coverage for prostate imaging. Coverage: {coverage:.0f} mm (need ≥60 mm). Found {num_slices} slices × {slice_thickness} mm.")
    elif coverage < 70:
        raise ValidationWarning(f"Slice coverage may be marginal for full prostate + marker coverage. Coverage: {coverage:.0f} mm. Target: ~80 mm (40 slices × 2 mm).")
